package com.hospital.management.validation;import com.hospital.management.model.PaymentForm;import org.junit.jupiter.api.*;import java.math.*;import static org.junit.jupiter.api.Assertions.*;class PaymentValidatorTest{PaymentValidator v=new PaymentValidator();private PaymentForm form(String method,String reference,String amount){PaymentForm f=new PaymentForm();f.setBillId(1L);f.setPaymentMethod(method);f.setTransactionReference(reference);f.setAmount(amount);return f;}@Test void acceptsCashAndUpi(){assertFalse(v.validate(form("CASH","","10"),BigDecimal.TEN).hasErrors());assertFalse(v.validate(form("UPI","UPI-REF","10"),BigDecimal.TEN).hasErrors());}@Test void requiresNonCashReference(){assertTrue(v.validate(form("UPI","","10"),BigDecimal.TEN).getErrors().containsKey("transactionReference"));}@Test void rejectsInvalidAndExcessAmount(){assertTrue(v.validate(form("CASH","","0"),BigDecimal.TEN).getErrors().containsKey("amount"));assertTrue(v.validate(form("CASH","","11"),BigDecimal.TEN).getErrors().containsKey("amount"));}@Test void rejectsUnknownMethod(){assertTrue(v.validate(form("CRYPTO","ref","1"),BigDecimal.TEN).getErrors().containsKey("paymentMethod"));}}
